(function () { 'use strict'; function initGalleryNavigation() { document.addEventListener('click', async e => { const link = e.target.closest('#galleryContent a[href*="album="]'); if (!link || e.metaKey || e.ctrlKey || e.shiftKey || e.altKey) { return; } const targetUrl = new URL(link.href, window.location.href); if (targetUrl.pathname !== window.location.pathname) { return; } e.preventDefault(); if (link.classList.contains('active') && !targetUrl.searchParams.has('all')) { return; } const scrollX = window.scrollX; const scrollY = window.scrollY; const currentContent = document.getElementById('galleryContent'); if (!currentContent) { window.location.href = link.href; return; } currentContent.setAttribute('aria-busy', 'true'); try { const fetchUrl = new URL(targetUrl); fetchUrl.hash = ''; const response = await fetch(fetchUrl.toString(), { headers: { 'X-Requested-With': 'XMLHttpRequest' }, }); if (!response.ok) { throw new Error('Album request failed'); } const html = await response.text(); const doc = new DOMParser().parseFromString(html, 'text/html'); const nextContent = doc.getElementById('galleryContent'); if (!nextContent) { throw new Error('Album content missing'); } currentContent.replaceWith(nextContent); window.history.pushState({}, '', fetchUrl.toString() + '#gallery'); window.scrollTo(scrollX, scrollY); } catch (error) { window.location.href = link.href; } finally { document.getElementById('galleryContent')?.removeAttribute('aria-busy'); } }); window.addEventListener('popstate', () => { window.location.reload(); }); } initGalleryNavigation(); const overlay = document.getElementById('lightbox'); const lightImg = document.getElementById('lightboxImg'); const closeBtn = document.getElementById('lightboxClose'); const prevBtn = document.getElementById('lightboxPrev'); const nextBtn = document.getElementById('lightboxNext'); if (!overlay) return; let items = []; let current = 0; function collectItems() { items = Array.from(document.querySelectorAll('.gallery-item[data-src]')); } function openLightbox(idx) { collectItems(); current = idx; showImage(); overlay.classList.add('active'); document.body.style.overflow = 'hidden'; closeBtn.focus(); } function closeLightbox() { overlay.classList.remove('active'); document.body.style.overflow = ''; } function showImage() { const item = items[current]; if (!item) return; lightImg.src = item.dataset.src; lightImg.alt = item.dataset.alt || ''; prevBtn.style.display = items.length <= 1 ? 'none' : ''; nextBtn.style.display = items.length <= 1 ? 'none' : ''; } function goNext() { current = (current + 1) % items.length; showImage(); } function goPrev() { current = (current - 1 + items.length) % items.length; showImage(); } document.addEventListener('click', e => { const item = e.target.closest('.gallery-item[data-src]'); if (item) { collectItems(); openLightbox(items.indexOf(item)); } }); document.addEventListener('keydown', e => { if (e.key === 'Enter' || e.key === ' ') { const item = document.activeElement?.closest('.gallery-item[data-src]'); if (item) { e.preventDefault(); collectItems(); openLightbox(items.indexOf(item)); } } if (!overlay.classList.contains('active')) return; if (e.key === 'Escape') closeLightbox(); if (e.key === 'ArrowRight') goNext(); if (e.key === 'ArrowLeft') goPrev(); }); closeBtn?.addEventListener('click', closeLightbox); nextBtn?.addEventListener('click', goNext); prevBtn?.addEventListener('click', goPrev); overlay.addEventListener('click', e => { if (e.target === overlay) closeLightbox(); }); })();